for book in books:
    if book['id'] in thoughts:
        book['thoughts'] = thoughts[book['id']]
    if book['id'] in descriptions:
        book['description'] = descriptions[book['id']]

with open('/root/books/webapp/books.json', 'w', encoding='utf-8') as f:
    json.dump(books, f, ensure_ascii=False, separators=(',', ':'))

print('Checking lengths:')
errors = []
for book in books:
    if book['id'] in thoughts:
        print(f"\n=== {book['id']} {book['title']} | desc={len(book['description'])} ===")
        for t in book['thoughts']:
            total = len(t['title']) + len(t['example'])
            status = 'OK' if 600 <= total <= 800 else f'FAIL({total})'
            print(f"  {status} - {t['title'][:40]}")
            if not (600 <= total <= 800):
                errors.append(f"{book['id']} / {t['title']}: {total}")
print(f"\nОшибок: {len(errors)}")
for e in errors:
    print(' ', e)
